    /// Uses Dictionary for O(1) lookups by ID, counter-based ID generation,
    /// single-pass statistics, and a HashSet for O(1) rented-movie checks.
    /// Late fee: $1.50 per day overdue.
    /// Default rental period: 7 days.
    /// Default daily rate: $3.99.
    /// </summary>
    public class InMemoryRentalRepository : IRentalRepository
    {
        /// <summary>Late fee per overdue day.</summary>
        public const decimal LateFeePerDay = 1.50m;

        /// <summary>Default rental duration in days.</summary>
        public const int DefaultRentalDays = 7;

        /// <summary>Default daily rental rate.</summary>
        public const decimal DefaultDailyRate = 3.99m;

        private static readonly Dictionary<int, Rental> _rentals;

        /// <summary>
        /// Tracks movie IDs that are currently rented out (not returned).
        /// Provides O(1) availability checks instead of scanning the full list.
        /// </summary>
        private static readonly HashSet<int> _rentedMovieIds;

        /// <summary>
        /// Tracks rental IDs that have been extended (each rental can only be extended once).
        /// </summary>
        private static readonly HashSet<int> _extendedRentalIds;

        private static readonly object _lock = new object();
        private static int _nextId;

        static InMemoryRentalRepository()
        {
            var seedData = new[]
            {
                new Rental
                {
                    Id = 1,
                    CustomerId = 1,
                    CustomerName = "John Smith",
                    MovieId = 1,
                    MovieName = "Shrek!",
                    RentalDate = DateTime.Today.AddDays(-3),
                    DueDate = DateTime.Today.AddDays(4),
                    DailyRate = 3.99m,
                    Status = RentalStatus.Active
                },
                new Rental
                {
                    Id = 2,
                    CustomerId = 2,
                    CustomerName = "Jane Doe",
                    MovieId = 2,
                    MovieName = "The Godfather",
                    RentalDate = DateTime.Today.AddDays(-10),
                    DueDate = DateTime.Today.AddDays(-3),
                    DailyRate = 3.99m,
                    Status = RentalStatus.Active
                },
                new Rental
                {
                    Id = 3,
                    CustomerId = 4,
                    CustomerName = "Alice Johnson",
                    MovieId = 3,
                    MovieName = "Toy Story",
                    RentalDate = DateTime.Today.AddDays(-14),
                    DueDate = DateTime.Today.AddDays(-7),
                    ReturnDate = DateTime.Today.AddDays(-6),
                    DailyRate = 3.99m,
                    LateFee = 0m,
                    Status = RentalStatus.Returned
                }
            };

            _rentals = new Dictionary<int, Rental>();
            _rentedMovieIds = new HashSet<int>();
            _extendedRentalIds = new HashSet<int>();

            foreach (var r in seedData)
            {
                _rentals[r.Id] = r;
                if (r.Status != RentalStatus.Returned)
                    _rentedMovieIds.Add(r.MovieId);
            }

            _nextId = 4;
        }

        public Rental GetById(int id)
        {
            lock (_lock)
            {
                if (!_rentals.TryGetValue(id, out var rental))
                    return null;

                RefreshStatus(rental);
                return Clone(rental);
            }
        }

        public IReadOnlyList<Rental> GetAll()
        {
            lock (_lock)
            {
                var result = new List<Rental>(_rentals.Count);
                foreach (var r in _rentals.Values)
                {
                    RefreshStatus(r);
                    result.Add(Clone(r));
                }
                return result.AsReadOnly();
            }
        }

        public void Add(Rental rental)
        {
            if (rental == null)
                throw new ArgumentNullException(nameof(rental));

            lock (_lock)
            {
                InitializeNewRental(rental);
            }
        }

        public void Update(Rental rental)
        {
            if (rental == null)
                throw new ArgumentNullException(nameof(rental));

            lock (_lock)
            {
                if (!_rentals.TryGetValue(rental.Id, out var existing))
                    throw new KeyNotFoundException(
                        $"Rental with Id {rental.Id} not found.");

                // If the movie changed or status changed, update the rented set
                if (existing.Status != RentalStatus.Returned)
                    _rentedMovieIds.Remove(existing.MovieId);

                existing.CustomerId = rental.CustomerId;
                existing.CustomerName = rental.CustomerName;
                existing.MovieId = rental.MovieId;
                existing.MovieName = rental.MovieName;
                existing.RentalDate = rental.RentalDate;
                existing.DueDate = rental.DueDate;
                existing.ReturnDate = rental.ReturnDate;
                existing.DailyRate = rental.DailyRate;
                existing.LateFee = rental.LateFee;
                existing.Status = rental.Status;

                if (existing.Status != RentalStatus.Returned)
                    _rentedMovieIds.Add(existing.MovieId);
            }
        }

        public void Remove(int id)
        {
            lock (_lock)
            {
                if (!_rentals.TryGetValue(id, out var rental))
                    throw new KeyNotFoundException(
                        $"Rental with Id {id} not found.");

                if (rental.Status != RentalStatus.Returned)
                    _rentedMovieIds.Remove(rental.MovieId);

                _rentals.Remove(id);
            }
        }

        public IReadOnlyList<Rental> GetByCustomer(int customerId)
        {
            return FilterAndSort(
                r => r.CustomerId == customerId,
                (a, b) => b.RentalDate.CompareTo(a.RentalDate));
        }

        public IReadOnlyList<Rental> GetActiveByCustomer(int customerId)
        {
            return FilterAndSort(
                r => r.CustomerId == customerId && r.Status != RentalStatus.Returned,
                (a, b) => a.DueDate.CompareTo(b.DueDate));
        }

        public IReadOnlyList<Rental> GetByMovie(int movieId)
        {
            return FilterAndSort(
                r => r.MovieId == movieId,
                (a, b) => b.RentalDate.CompareTo(a.RentalDate));
        }

        public IReadOnlyList<Rental> GetOverdue()
        {
            return FilterAndSort(
                r => r.Status == RentalStatus.Overdue,
                (a, b) => a.DueDate.CompareTo(b.DueDate));
        }

        public IReadOnlyList<Rental> Search(string query, RentalStatus? status)
        {
            bool hasQuery = !string.IsNullOrWhiteSpace(query);

            return FilterAndSort(
                r =>
                {
                    if (hasQuery)
                    {
                        bool matchesCustomer = r.CustomerName != null &&
                            r.CustomerName.IndexOf(query, StringComparison.OrdinalIgnoreCase) >= 0;
                        bool matchesMovie = r.MovieName != null &&
                            r.MovieName.IndexOf(query, StringComparison.OrdinalIgnoreCase) >= 0;

                        if (!matchesCustomer && !matchesMovie)
                            return false;
                    }

                    if (status.HasValue && r.Status != status.Value)
                        return false;

                    return true;
                },
                (a, b) => b.RentalDate.CompareTo(a.RentalDate));
        }

        /// <summary>
        /// Shared helper that acquires the lock, iterates all rentals with
        /// status refresh, applies a predicate filter, clones matches, and
        /// sorts the result.  Eliminates the repeated lock-iterate-filter-
        /// clone-sort pattern across query methods.
        /// </summary>
        private IReadOnlyList<Rental> FilterAndSort(
            Func<Rental, bool> predicate,
            Comparison<Rental> sortComparison)
        {
            lock (_lock)
            {
                var result = new List<Rental>();
                foreach (var r in _rentals.Values)
                {
                    RefreshStatus(r);
                    if (predicate(r))
                        result.Add(Clone(r));
                }
                result.Sort(sortComparison);
                return result.AsReadOnly();
            }
        }

        public Rental ReturnRental(int rentalId)
        {
            lock (_lock)
            {
                if (!_rentals.TryGetValue(rentalId, out var rental))
                    throw new KeyNotFoundException(
                        $"Rental with Id {rentalId} not found.");

                if (rental.Status == RentalStatus.Returned)
                    throw new InvalidOperationException(
                        $"Rental {rentalId} has already been returned.");

                rental.ReturnDate = DateTime.Today;
                rental.Status = RentalStatus.Returned;

                // Remove from rented set for O(1) availability checks
                _rentedMovieIds.Remove(rental.MovieId);

                // Calculate late fee
                if (rental.ReturnDate.Value > rental.DueDate)
                {
                    var overdueDays = (int)Math.Ceiling((rental.ReturnDate.Value - rental.DueDate).TotalDays);
                    rental.LateFee = overdueDays * LateFeePerDay;
                }
                else
                {
                    rental.LateFee = 0;
                }

                return Clone(rental);
            }
        }

        /// <summary>
        /// O(1) movie availability check using the rented movie ID set.
        /// </summary>
        public bool IsMovieRentedOut(int movieId)
        {
            lock (_lock)
            {
                return _rentedMovieIds.Contains(movieId);
            }
        }

        public Rental Checkout(Rental rental)
        {
            return Checkout(rental, int.MaxValue);
        }

        public Rental Checkout(Rental rental, int maxConcurrentRentals)
        {
            if (rental == null)
                throw new ArgumentNullException(nameof(rental));

            lock (_lock)
            {
                // O(1) availability check via HashSet
                if (_rentedMovieIds.Contains(rental.MovieId))
                {
                    throw new InvalidOperationException(
                        "This movie is currently rented out.");
                }

                // Enforce membership tier concurrent rental limit.
                // Count both Active AND Overdue rentals — overdue movies are still
                // checked out and must count against the limit. Previously only
                // Active was counted, so customers with overdue rentals could bypass
                // the cap by letting their rentals go overdue (bug fix).
                if (maxConcurrentRentals < int.MaxValue)
                {
                    // Only refresh and count rentals for this specific customer
                    // instead of refreshing ALL rentals (O(N) → O(K) where K is
                    // the customer's rental count).
                    int outstandingCount = 0;
                    foreach (var r in _rentals.Values)
                    {
                        if (r.CustomerId != rental.CustomerId)
                            continue;
                        RefreshStatus(r);
                        if (r.Status != RentalStatus.Returned)
                            outstandingCount++;
                    }
                    if (outstandingCount >= maxConcurrentRentals)
                    {
                        throw new InvalidOperationException(
                            $"Customer has reached their concurrent rental limit of {maxConcurrentRentals}.");
                    }
                }

                InitializeNewRental(rental);
                return Clone(rental);
            }
        }

        /// <summary>
        /// Shared initialization for new rentals: assigns ID, applies defaults,
        /// sets status, and registers in storage + rented movie set.
        /// Must be called within a lock.
        /// </summary>
        private static void InitializeNewRental(Rental rental)
        {
            rental.Id = _nextId++;

            if (rental.DailyRate <= 0)
                rental.DailyRate = DefaultDailyRate;

            if (rental.RentalDate == default)
                rental.RentalDate = DateTime.Today;

            if (rental.DueDate == default)
                rental.DueDate = rental.RentalDate.AddDays(DefaultRentalDays);

            rental.Status = RentalStatus.Active;
            rental.ReturnDate = null;
            rental.LateFee = 0;

            _rentals[rental.Id] = rental;
            _rentedMovieIds.Add(rental.MovieId);
        }

        /// <summary>
        /// Extends an active rental's due date. Each rental can only be extended once.
        /// Extension fee: half the daily rate per extension day.
        /// </summary>
        public Rental ExtendRental(int rentalId, int days)
        {
            if (days < 1 || days > 7)
                throw new ArgumentOutOfRangeException(nameof(days),
                    "Extension must be between 1 and 7 days.");

            lock (_lock)
            {
                if (!_rentals.TryGetValue(rentalId, out var rental))
                    throw new KeyNotFoundException(
                        $"Rental with Id {rentalId} not found.");

                RefreshStatus(rental);

                if (rental.Status == RentalStatus.Returned)
                    throw new InvalidOperationException(
                        "Cannot extend a rental that has already been returned.");

                if (_extendedRentalIds.Contains(rentalId))
                    throw new InvalidOperationException(
                        "This rental has already been extended. Each rental can only be extended once.");

                // Extension fee: half the daily rate per extension day
                var extensionFee = Math.Round(rental.DailyRate * 0.5m * days, 2);

                rental.DueDate = rental.DueDate.AddDays(days);
                // Add extension fee as a bump to the effective daily rate over the rental period
                var totalDays = Math.Max(1, (int)Math.Ceiling((rental.DueDate - rental.RentalDate).TotalDays));
                rental.DailyRate = Math.Round((rental.DailyRate * (totalDays - days) + rental.DailyRate * days + extensionFee) / totalDays, 2);

                // Refresh status after extending (may no longer be overdue)
                if (rental.Status == RentalStatus.Overdue && DateTime.Today <= rental.DueDate)
                {
                    rental.Status = RentalStatus.Active;
                    rental.LateFee = 0;
                }

                _extendedRentalIds.Add(rentalId);
                return Clone(rental);
            }
        }

        /// <summary>
        /// Checks whether a rental has already been extended.
        /// </summary>
        public bool IsExtended(int rentalId)
        {
            lock (_lock)
            {
                return _extendedRentalIds.Contains(rentalId);
            }
        }

        /// <summary>
        /// Computes rental statistics in a single pass over the collection,
        /// avoiding multiple separate Count()/Sum() enumerations.
        /// </summary>
        public RentalStats GetStats()
        {
            lock (_lock)
            {
                int active = 0, overdue = 0, returned = 0;
                decimal totalRevenue = 0, totalLateFees = 0;
                decimal realizedRevenue = 0, projectedRevenue = 0;

                foreach (var r in _rentals.Values)
                {
                    RefreshStatus(r);

                    switch (r.Status)
                    {
                        case RentalStatus.Returned:
                            returned++;
                            totalRevenue += r.TotalCost;
                            realizedRevenue += r.TotalCost;
                            totalLateFees += r.LateFee;
                            break;
                        case RentalStatus.Active:
                            active++;
                            totalRevenue += r.TotalCost;
                            projectedRevenue += r.TotalCost;
                            break;
                        case RentalStatus.Overdue:
                            overdue++;
                            totalRevenue += r.TotalCost;
                            projectedRevenue += r.TotalCost;
                            totalLateFees += r.LateFee;
                            break;
                    }
                }

                return new RentalStats
                {
                    TotalRentals = _rentals.Count,
                    ActiveRentals = active,
                    OverdueRentals = overdue,
                    ReturnedRentals = returned,
                    TotalRevenue = totalRevenue,
                    RealizedRevenue = realizedRevenue,
                    ProjectedRevenue = projectedRevenue,
                    TotalLateFees = totalLateFees
                };
            }
        }

        /// <summary>
        /// Auto-update status and accruing late fee based on dates.
        /// Previously only flipped Active → Overdue but left LateFee at 0,
        /// causing GetStats(), dashboard summaries, and billing views to
        /// undercount late fees for unreturned overdue rentals (bug fix).
        /// </summary>
        private static void RefreshStatus(Rental rental)
        {
            if (rental.Status == RentalStatus.Returned)
                return;

            if (DateTime.Today > rental.DueDate)
            {
                rental.Status = RentalStatus.Overdue;
                var overdueDays = (int)Math.Ceiling((DateTime.Today - rental.DueDate).TotalDays);
                rental.LateFee = overdueDays * LateFeePerDay;
            }
        }

        /// <summary>
        /// Resets the repository to its initial seed state for test isolation.
        /// </summary>
        public static void Reset()
        {
            lock (_lock)
            {
                _rentals.Clear();
                _rentedMovieIds.Clear();
                _extendedRentalIds.Clear();

                var seedData = new[]
                {
                    new Rental { Id = 1, CustomerId = 1, CustomerName = "John Smith", MovieId = 1, MovieName = "Shrek!", RentalDate = DateTime.Today.AddDays(-3), DueDate = DateTime.Today.AddDays(4), DailyRate = 3.99m, Status = RentalStatus.Active },
                    new Rental { Id = 2, CustomerId = 2, CustomerName = "Jane Doe", MovieId = 2, MovieName = "The Godfather", RentalDate = DateTime.Today.AddDays(-10), DueDate = DateTime.Today.AddDays(-3), DailyRate = 3.99m, Status = RentalStatus.Active },
                    new Rental { Id = 3, CustomerId = 4, CustomerName = "Alice Johnson", MovieId = 3, MovieName = "Toy Story", RentalDate = DateTime.Today.AddDays(-14), DueDate = DateTime.Today.AddDays(-7), ReturnDate = DateTime.Today.AddDays(-6), DailyRate = 3.99m, LateFee = 0m, Status = RentalStatus.Returned }
                };

                foreach (var r in seedData)
                {
                    _rentals[r.Id] = r;
                    if (r.Status != RentalStatus.Returned)
                        _rentedMovieIds.Add(r.MovieId);
                }

                _nextId = 4;
            }
        }

        /// <summary>
        /// Creates a defensive copy.
        /// </summary>
        private static Rental Clone(Rental source)
        {
            return new Rental
            {
                Id = source.Id,
                CustomerId = source.CustomerId,
                CustomerName = source.CustomerName,
                MovieId = source.MovieId,
                MovieName = source.MovieName,
                RentalDate = source.RentalDate,
                DueDate = source.DueDate,
                ReturnDate = source.ReturnDate,
                DailyRate = source.DailyRate,
                LateFee = source.LateFee,
                Status = source.Status
            };
        }
    }
}

